export enum Speaker {
  Host = 'Host',
  Expert = 'Expert'
}

export interface ScriptLine {
  speaker: Speaker;
  text: string;
}

export enum AppState {
  Idle = 'idle',
  GeneratingScript = 'generating_script',
  ScriptReady = 'script_ready',
  GeneratingAudio = 'generating_audio',
  Playing = 'playing',
  Error = 'error'
}

export interface PodcastConfig {
  hostName: string;
  expertName: string;
  tone: 'Professional' | 'Casual' | 'Funny';
}

export const base64ToArrayBuffer = (base64: string): ArrayBuffer => {
  const binaryString = window.atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
};

// Simple WAV header generator for raw PCM data (16-bit, mono, 24kHz)
export const createWavHeader = (dataLength: number, sampleRate: number = 24000, numChannels: number = 1): ArrayBuffer => {
  const buffer = new ArrayBuffer(44);
  const view = new DataView(buffer);

  // RIFF identifier
  writeString(view, 0, 'RIFF');
  // file length
  view.setUint32(4, 36 + dataLength, true);
  // RIFF type
  writeString(view, 8, 'WAVE');
  // format chunk identifier
  writeString(view, 12, 'fmt ');
  // format chunk length
  view.setUint32(16, 16, true);
  // sample format (raw)
  view.setUint16(20, 1, true);
  // channel count
  view.setUint16(22, numChannels, true);
  // sample rate
  view.setUint32(24, sampleRate, true);
  // byte rate (sampleRate * blockAlign)
  view.setUint32(28, sampleRate * numChannels * 2, true);
  // block align (channel count * bytes per sample)
  view.setUint16(32, numChannels * 2, true);
  // bits per sample
  view.setUint16(34, 16, true);
  // data chunk identifier
  writeString(view, 36, 'data');
  // data chunk length
  view.setUint32(40, dataLength, true);

  return buffer;
};

const writeString = (view: DataView, offset: number, string: string) => {
  for (let i = 0; i < string.length; i++) {
    view.setUint8(offset + i, string.charCodeAt(i));
  }
};

export const createWavBlob = (pcmData: ArrayBuffer, sampleRate: number = 24000): Blob => {
  const header = createWavHeader(pcmData.byteLength, sampleRate);
  return new Blob([header, pcmData], { type: 'audio/wav' });
};

import { GoogleGenAI, Modality } from "@google/genai";
import { PodcastConfig, ScriptLine, Speaker } from "../types";

// Initialize Gemini Client
// Note: API Key must be in process.env.API_KEY
const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment variables.");
  }
  return new GoogleGenAI({ apiKey });
};

export const generatePodcastScript = async (
  text: string,
  config: PodcastConfig
): Promise<ScriptLine[]> => {
  const ai = getClient();
  const model = "gemini-2.5-flash";

  const prompt = `
    You are an expert podcast producer. Your task is to convert the provided input text into a engaging, natural-sounding podcast dialogue between two hosts: ${config.hostName} (Host) and ${config.expertName} (Expert).

    Tone: ${config.tone}.

    Rules:
    1. The Host introduces the topic and asks guiding questions.
    2. The Expert explains the concepts from the text in an accessible way.
    3. Keep it conversational. Use fillers like "Exactly", "That's a great point", etc., but don't overdo it.
    4. The output MUST be a valid JSON array of objects with "speaker" ("Host" or "Expert") and "text" fields.
    5. Do not include any markdown formatting like \`\`\`json. Just the raw JSON.
    6. If the text is very long, summarize the key points into a 5-10 minute conversation.

    Input Text:
    "${text.slice(0, 30000)}" 
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      },
    });

    const jsonStr = response.text || "[]";
    const script = JSON.parse(jsonStr) as { speaker: string; text: string }[];

    // Validate and map to ScriptLine
    return script.map(s => ({
      speaker: s.speaker === 'Host' || s.speaker === config.hostName ? Speaker.Host : Speaker.Expert,
      text: s.text
    }));

  } catch (error) {
    console.error("Error generating script:", error);
    throw error;
  }
};

export const generatePodcastAudio = async (
  script: ScriptLine[],
  config: PodcastConfig
): Promise<string> => {
  const ai = getClient();
  const model = "gemini-2.5-flash-preview-tts";

  // Format the script into the text format Gemini expects for multi-speaker
  // "Speaker: Text"
  const textPrompt = script.map(line => {
    const name = line.speaker === Speaker.Host ? config.hostName : config.expertName;
    return `${name}: ${line.text}`;
  }).join('\n\n');

  const fullPrompt = `Generate a podcast audio for the following conversation between ${config.hostName} and ${config.expertName}.\n\n${textPrompt}`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: fullPrompt,
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              {
                speaker: config.hostName,
                voiceConfig: {
                  prebuiltVoiceConfig: { voiceName: 'Puck' } // Deep, authoritative for Host
                }
              },
              {
                speaker: config.expertName,
                voiceConfig: {
                  prebuiltVoiceConfig: { voiceName: 'Fenrir' } // Clear, energetic for Expert
                }
              }
            ]
          }
        }
      }
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    if (!base64Audio) {
      throw new Error("No audio data returned from Gemini.");
    }

    return base64Audio;

  } catch (error) {
    console.error("Error generating audio:", error);
    throw error;
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger';
  isLoading?: boolean;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading = false, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyle = "px-6 py-3 rounded-xl font-semibold transition-all duration-200 flex items-center justify-center gap-2 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-900";

  const variants = {
    primary: "bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-500/30 focus:ring-indigo-500 border border-transparent",
    secondary: "bg-gray-800 hover:bg-gray-700 text-gray-200 border border-gray-700 focus:ring-gray-500",
    danger: "bg-red-600 hover:bg-red-500 text-white focus:ring-red-500"
  };

  return (
    <button
      className={`${baseStyle} ${variants[variant]} ${disabled || isLoading ? 'opacity-50 cursor-not-allowed' : 'active:scale-95'} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing...
        </>
      ) : children}
    </button>
  );
};

export default Button;

