            }`}>
              {line.speaker === Speaker.Host ? <User size={20} /> : <Bot size={20} />}
            </div>
            <div className={`flex flex-col max-w-[80%] ${line.speaker === Speaker.Host ? 'items-start' : 'items-end'}`}>
