};

export default ScriptViewer;

import React, { useEffect, useRef, useState } from 'react';
import { Play, Pause, Download, Volume2, Music4 } from 'lucide-react';
import Button from './Button';
import { base64ToArrayBuffer, createWavBlob } from '../utils/audioUtils';

interface AudioPlayerProps {
  base64Audio: string;
}

const AudioPlayer: React.FC<AudioPlayerProps> = ({ base64Audio }) => {
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [blobUrl, setBlobUrl] = useState<string | null>(null);

  useEffect(() => {
    // Convert base64 to blob URL
    const pcmData = base64ToArrayBuffer(base64Audio);
    const wavBlob = createWavBlob(pcmData);
    const url = URL.createObjectURL(wavBlob);
    setBlobUrl(url);

    return () => {
      URL.revokeObjectURL(url);
    };
  }, [base64Audio]);

  useEffect(() => {
    if (!blobUrl || !canvasRef.current || !audioRef.current) return;

    // Visualizer setup would go here (omitted for brevity, just using animation)
    // For a real visualizer, we'd need an AudioContext and AnalyserNode connected to the audio element.
  }, [blobUrl]);

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const handleTimeUpdate = () => {
    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
    }
  };

  const handleLoadedMetadata = () => {
    if (audioRef.current) {
      setDuration(audioRef.current.duration);
    }
  };

  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds.toString().padStart(2, '0')}`;
  };

  const handleDownload = () => {
    if (blobUrl) {
      const a = document.createElement('a');
      a.href = blobUrl;
      a.download = 'podcast.wav';
      a.click();
    }
  };

  return (
    <div className="bg-gray-900 border border-gray-800 rounded-2xl p-6 shadow-2xl">
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
            <div className="p-3 bg-rose-500/10 rounded-full">
                <Music4 className="text-rose-500" size={24} />
            </div>
            <div>
                <h3 className="font-semibold text-white">Interview Guide Podcast</h3>
                <p className="text-sm text-gray-500">Generated by Gemini</p>
            </div>
        </div>
        <button 
            onClick={handleDownload}
            className="p-2 hover:bg-gray-800 rounded-full transition-colors text-gray-400 hover:text-white"
            title="Download WAV"
        >
            <Download size={20} />
        </button>
      </div>

      {/* Visualizer Placeholder */}
      <div className="h-24 bg-gray-950 rounded-xl mb-6 flex items-center justify-center relative overflow-hidden group">
         <div className="absolute inset-0 flex items-center justify-center gap-1 opacity-50">
            {[...Array(20)].map((_, i) => (
                <div 
                    key={i} 
                    className={`w-1.5 bg-indigo-500 rounded-full transition-all duration-300 ${isPlaying ? 'animate-pulse' : 'h-2'}`}
                    style={{ 
                        height: isPlaying ? `${Math.random() * 80 + 20}%` : '10%',
                        animationDelay: `${i * 0.05}s`
                    }}
                />
            ))}
         </div>
      </div>

      {/* Controls */}
      <div className="flex flex-col gap-4">
        <div className="flex items-center gap-4">
            <span className="text-xs text-gray-400 font-mono w-10">{formatTime(currentTime)}</span>
            <input 
                type="range" 
                min="0" 
                max={duration || 100} 
                value={currentTime} 
                onChange={(e) => {
                    const time = parseFloat(e.target.value);
                    if (audioRef.current) audioRef.current.currentTime = time;
                    setCurrentTime(time);
                }}
                className="flex-1 h-1.5 bg-gray-800 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white"
            />
            <span className="text-xs text-gray-400 font-mono w-10">{formatTime(duration)}</span>
        </div>

        <div className="flex justify-center">
             <button 
                onClick={togglePlay}
                className="w-14 h-14 bg-white rounded-full flex items-center justify-center text-black hover:scale-105 transition-transform shadow-lg shadow-white/20"
             >
                {isPlaying ? <Pause fill="currentColor" /> : <Play fill="currentColor" className="ml-1" />}
             </button>
        </div>
      </div>

      {blobUrl && (
        <audio 
            ref={audioRef} 
            src={blobUrl} 
            onTimeUpdate={handleTimeUpdate}
            onLoadedMetadata={handleLoadedMetadata}
            onEnded={() => setIsPlaying(false)}
            className="hidden"
        />
      )}
    </div>
  );
};

export default AudioPlayer;

import React, { useState } from 'react';
import Header from './components/Header';
import Button from './components/Button';
import ScriptViewer from './components/ScriptViewer';
import AudioPlayer from './components/AudioPlayer';
import { generatePodcastScript, generatePodcastAudio } from './services/geminiService';
import { AppState, PodcastConfig, ScriptLine } from './types';
import { Wand2, FileText, Headphones } from 'lucide-react';

// Pre-fill text from the prompt for convenience
const DEMO_TEXT = `Preparation for Job Interviews
1. Appreciation: Immediately express appreciation to the hiring manager for the opportunity.
2. Honest and Succinct: Be honest, stick to the point, be positive.
3. Sales Pitch: Explain what you offer and why you should get the job.

Top 10 Interview Questions and Best Answers
1. Tell Me About Yourself: Talk about why you're an ideal candidate, not personal details. Share hobbies only if relevant or to show personality (e.g., charity walks).
2. Why Are You the Best Person for the Job?: Match qualifications to job posting. Emphasize unique skills.
3. Why Do You Want This Job?: Research the company. Explain how you fit the mission.
4. How Has Your Experience Prepared You?: Use the STAR method. Connect past responsibilities to new requirements.
5. Why Are You Leaving?: Be honest but positive. Don't badmouth previous employers.
6. What Is Your Greatest Strength?: Show, don't just tell. Use anecdotes.
7. What Is Your Greatest Weakness?: Mention non-essential skills or skills you've improved. Turn negatives into positives (e.g., perfectionism -> detail-oriented).
8. How Do You Handle Stress?: Give examples of handling pressure productively.
9. Salary Expectations?: Research beforehand. Offer a range. Be flexible but know your worth.
10. Future Goals?: Connect personal goals to the company's future.`;

const App: React.FC = () => {
  const [text, setText] = useState<string>('');
  const [appState, setAppState] = useState<AppState>(AppState.Idle);
  const [script, setScript] = useState<ScriptLine[]>([]);
  const [audioBase64, setAudioBase64] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const config: PodcastConfig = {
    hostName: 'Kore',
    expertName: 'Fenrir',
    tone: 'Professional'
  };

  const handleGenerateScript = async () => {
    if (!text.trim()) return;

    setAppState(AppState.GeneratingScript);
    setError(null);
    try {
      const generatedScript = await generatePodcastScript(text, config);
      setScript(generatedScript);
      setAppState(AppState.ScriptReady);
    } catch (err: any) {
      console.error(err);
      setError("Failed to generate script. Please try again.");
      setAppState(AppState.Error);
    }
  };

  const handleGenerateAudio = async () => {
    if (script.length === 0) return;

    setAppState(AppState.GeneratingAudio);
    setError(null);
    try {
      const audio = await generatePodcastAudio(script, config);
      setAudioBase64(audio);
      setAppState(AppState.Playing);
    } catch (err: any) {
      console.error(err);
      setError("Failed to generate audio. The content might be too long for a single pass.");
      setAppState(AppState.Error);
    }
  };

  const handleLoadDemo = () => {
    setText(DEMO_TEXT);
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 selection:bg-indigo-500/30">
      <Header />

      <main className="max-w-5xl mx-auto px-4 pb-20">

        {/* Intro / Hero */}
        <div className="text-center my-12">
          <h2 className="text-4xl md:text-5xl font-bold text-white mb-4 tracking-tight">
            Turn Documents into <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-400">Podcasts</span>
          </h2>
          <p className="text-lg text-slate-400 max-w-2xl mx-auto">
            Paste your interview guide, article, or notes below. Gemini will script a conversation and record it with lifelike voices.
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Left Column: Input & Controls */}
          <div className="space-y-6">
            <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-xl">
              <div className="relative">
                <textarea
                  className="w-full h-96 bg-slate-950/50 text-slate-300 p-6 rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500/50 border-none placeholder:text-slate-600 leading-relaxed custom-scrollbar"
                  placeholder="Paste your text here..."
                  value={text}
                  onChange={(e) => setText(e.target.value)}
                  disabled={appState === AppState.GeneratingScript || appState === AppState.GeneratingAudio}
                />
                {text.length === 0 && (
                   <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                      <button 
                        onClick={(e) => { e.stopPropagation(); handleLoadDemo(); }} 
                        className="pointer-events-auto px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 text-sm rounded-lg border border-slate-700 transition-colors shadow-lg"
                      >
                        Load "Job Interview Guide" Example
                      </button>
                   </div>
                )}
                <div className="absolute bottom-4 right-4 text-xs text-slate-600 bg-slate-900/80 px-2 py-1 rounded">
                  {text.length} chars
                </div>
              </div>
            </div>

            <div className="flex gap-4">
               <Button 
                onClick={handleGenerateScript} 
                disabled={!text || appState === AppState.GeneratingScript || appState === AppState.GeneratingAudio}
                isLoading={appState === AppState.GeneratingScript}
                className="flex-1"
               >
                 <FileText size={18} />
                 {script.length > 0 ? 'Regenerate Script' : 'Generate Script'}
               </Button>
            </div>

            {error && (
              <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-sm text-center">
                {error}
              </div>
            )}
          </div>

          {/* Right Column: Output */}
          <div className="space-y-6">

            {/* Step 1: Script View */}
            {script.length > 0 && (
              <div className="animate-fade-in-up">
                <ScriptViewer script={script} />

                <div className="mt-6 flex justify-end">
                   <Button 
                    onClick={handleGenerateAudio}
                    isLoading={appState === AppState.GeneratingAudio}
                    disabled={appState === AppState.GeneratingAudio}
                    variant="primary"
                    className="w-full bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500 shadow-emerald-500/20"
                   >
                     <Headphones size={18} />
                     Generate Audio (Podcast)
                   </Button>
                </div>
              </div>
            )}

            {/* Step 2: Audio Player */}
            {audioBase64 && (
              <div className="animate-fade-in-up">
                 <div className="h-px bg-slate-800 my-8" />
                 <h3 className="text-xl font-semibold text-white mb-4">Your Podcast</h3>
                 <AudioPlayer base64Audio={audioBase64} />
              </div>
            )}

            {appState === AppState.Idle && script.length === 0 && (
               <div className="h-full flex flex-col items-center justify-center text-slate-600 border-2 border-dashed border-slate-800 rounded-2xl p-12 bg-slate-900/30">
                  <Wand2 size={48} className="mb-4 opacity-50" />
                  <p>Your podcast script and audio will appear here.</p>
               </div>
            )}
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI, Modality } from "@google/genai";
import { PodcastConfig, ScriptLine, Speaker } from "../types";

// Initialize Gemini Client
// Note: API Key must be in process.env.API_KEY
const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please check your environment variables.");
  }
  return new GoogleGenAI({ apiKey });
};

export interface GenerateScriptInput {
  text?: string;
  pdfBase64?: string;
}

export const generatePodcastScript = async (
  input: GenerateScriptInput,
  config: PodcastConfig
): Promise<ScriptLine[]> => {
  const ai = getClient();
  const model = "gemini-2.5-flash";

  const systemInstruction = `
    You are an expert podcast producer. Your task is to convert the provided input (text or document) into an engaging, natural-sounding podcast dialogue between two hosts: ${config.hostName} (Host) and ${config.expertName} (Expert).

    Tone: ${config.tone}.

    Rules:
    1. The Host introduces the topic and asks guiding questions.
    2. The Expert explains the concepts from the text in an accessible way.
    3. Keep it conversational. Use fillers like "Exactly", "That's a great point", etc., but don't overdo it.
    4. The output MUST be a valid JSON array of objects with "speaker" ("Host" or "Expert") and "text" fields.
    5. Do not include any markdown formatting like \`\`\`json. Just the raw JSON.
    6. CRITICAL: Do NOT summarize the content. You must cover the ENTIRETY of the provided input material in detail. Convert the full document into dialogue without omitting sections.
    7. If the content is long, create a comprehensive script that covers everything.
  `;

  let contents: any[] = [];

  if (input.pdfBase64) {
    contents = [
      { text: "Convert this PDF document into a podcast script following the system instructions. Cover the whole document." },
      { 
        inlineData: { 
          mimeType: "application/pdf", 
          data: input.pdfBase64 
        } 
      }
    ];
  } else if (input.text) {
    contents = [{ text: input.text }];
  } else {
    throw new Error("No input provided");
  }

  try {
    const response = await ai.models.generateContent({
      model,
      contents,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        maxOutputTokens: 8192, // Increased limit to allow for full length scripts
      },
    });

    const jsonStr = response.text || "[]";
    const script = JSON.parse(jsonStr) as { speaker: string; text: string }[];

    // Validate and map to ScriptLine
    return script.map(s => ({
      speaker: s.speaker === 'Host' || s.speaker === config.hostName ? Speaker.Host : Speaker.Expert,
      text: s.text
    }));

  } catch (error) {
    console.error("Error generating script:", error);
